import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Fixed code with proper input validation
        byte[] buffer = new byte[10];
        int length = Math.min(userInput.length(), buffer.length);
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, length);

        System.out.println("Buffer overflow vulnerability fixed!");
    }
}

